import os
from pip_requirements_parser import read_requirements
from pip_compile import write_file

def manage_dependency(lock_file):
    if not os.path.exists(lock_file):
        print("Lock file does not exist")
        return
    
    requirements = read_requirements(lock_file)
    
    for requirement in requirements:
        print(f"Updating {requirement.name} to version {requirement.specs[0][1]}")
        
    write_file(lock_file, sorted([str(r) for r in requirements]))

def main():
    lock_files = ["requirements.txt", "poetry.lock"]  # Add more if needed
    
    for file in lock_files:
        manage_dependency(file)

if __name__ == "__main__":
    main()